export type SnackbarVertical = 'top' | 'bottom';
export type SnackbarHorizontal = 'left' | 'center' | 'right';

export interface SnackbarConfig {
  content: React.ReactNode;
  uid?: string;
  backgroundColor?: string;
  textColor?: string;
  vertical?: SnackbarVertical;
  horizontal?: SnackbarHorizontal;
  autoDismiss?: number; // can set to Infinity for persistent snacks, 3000ms by default
  componentId?: string; // for analytics events
  closeButton?: boolean; // if false, removes the close button
}

export interface SnackbarWithId extends SnackbarConfig {
  id: string;
  open: boolean;
}

type Listener = () => void;

/**
 * SnackBarManager is a store for managing SnackBar state.
 * It maintains the list of active snacks and notifies subscribers when state changes.
 */
class SnackBarManager {
  private snacks: SnackbarWithId[] = [];
  private listeners = new Set<Listener>();

  subscribe = (listener: Listener): (() => void) => {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  };

  getSnapshot = (): SnackbarWithId[] => {
    return this.snacks;
  };

  private notifyListeners(): void {
    this.listeners.forEach((listener) => listener());
  }

  // Adds a snack and returns its ID.
  addSnack(config: SnackbarConfig): string {
    const snackId = config.uid ?? crypto.randomUUID();

    if (this.doesSnackExist(snackId)) {
      return snackId;
    }

    const snack: SnackbarWithId = {
      ...config,
      id: snackId,
      open: true,
      vertical: config.vertical || 'top',
      horizontal: config.horizontal || 'center',
      autoDismiss: config.autoDismiss ?? 3000,
    };

    this.snacks = [...this.snacks, snack];
    this.notifyListeners();

    return snackId;
  }

  // Closes a snack by ID
  closeSnack(id: string): void {
    if (!this.doesSnackExist(id)) {
      return;
    }
    this.snacks = this.snacks.map((snack) => (snack.id === id ? { ...snack, open: false } : snack));
    this.notifyListeners();
  }

  // Deletes a snack by ID (after close animation)
  deleteSnack(id: string): void {
    if (!this.doesSnackExist(id)) {
      return;
    }
    this.snacks = this.snacks.filter((snack) => snack.id !== id);
    this.notifyListeners();
  }

  // Checks if a snack with the given ID exists
  doesSnackExist(id: string): boolean {
    return this.snacks.some((snack) => snack.id === id);
  }

  reset(): void {
    this.snacks = [];
    this.notifyListeners();
  }
}

export const snackBarManager = new SnackBarManager();
