import { useCallback } from 'react';

import type { SnackbarConfig } from './SnackBarManager';
import { snackBarManager } from './SnackBarManager';

/**
 * Hook to interact with the SnackBar system.
 * Use this hook to add and close snackbars.
 */
export function useSnackBar() {
  const addSnack = useCallback((config: SnackbarConfig) => {
    return snackBarManager.addSnack(config);
  }, []);

  const closeSnack = useCallback((id: string) => {
    snackBarManager.closeSnack(id);
  }, []);

  return { addSnack, closeSnack };
}
