import type { SerializedStyles } from '@emotion/react';
import { css, keyframes } from '@emotion/react';
import * as Toast from '@radix-ui/react-toast';
import React, { forwardRef, useCallback, useMemo } from 'react';
import { useSyncExternalStore } from 'use-sync-external-store/shim';

import type { SnackbarVertical, SnackbarHorizontal, SnackbarWithId } from './SnackBarManager';
import { snackBarManager } from './SnackBarManager';
import type { Theme } from '../../theme';
import { primitiveColors } from '../../theme/_generated/PrimitiveColors';
import { Button } from '../Button';
import {
  DesignSystemEventProviderAnalyticsEventTypes,
  DesignSystemEventProviderComponentTypes,
  useDesignSystemEventComponentCallbacks,
} from '../DesignSystemEventProvider/DesignSystemEventProvider';
import { DU_BOIS_ENABLE_ANIMATION_CLASSNAME } from '../DesignSystemProvider';
import { useDesignSystemTheme } from '../Hooks';
import { CloseIcon } from '../Icon';
import { useNotifyOnFirstView } from '../utils';
import { addDebugOutlineIfEnabled } from '../utils/debug';

const getCloseButtonStyles = (theme: Theme): SerializedStyles => {
  return css({
    marginLeft: theme.spacing.sm,
    flexShrink: 0,
    // Override design system colors to use dark mode colors in both light and dark modes for proper contrast
    '&&:enabled:not(.du-bois-light-btn-link) > .anticon': {
      color: `${primitiveColors.grey100} !important`,
    },
    '&&:enabled:not(.du-bois-light-btn-link):hover > .anticon': {
      color: `${primitiveColors.blue400} !important`,
    },
    '&&:enabled:not(.du-bois-light-btn-link):active > .anticon': {
      color: `${primitiveColors.blue300} !important`,
    },
  });
};

const fadeInAnimation = keyframes({
  from: {
    opacity: 0,
  },
  to: {
    opacity: 1,
  },
});

const fadeOutAnimation = keyframes({
  from: {
    opacity: 1,
  },
  to: {
    opacity: 0,
  },
});

const getSnackBarRootStyle = (theme: Theme, backgroundColor?: string, textColor?: string): SerializedStyles => {
  const defaultBackgroundColor = theme.isDarkMode ? theme.colors.grey600 : theme.colors.grey800;
  const defaultTextColor = theme.colors.white;

  return css({
    '&&': {
      position: 'relative',
      display: 'flex',
      alignItems: 'center',
      padding: '12px 16px',
      backgroundColor: backgroundColor || defaultBackgroundColor,
      color: textColor || defaultTextColor,
      boxShadow: theme.shadows.lg,
      borderRadius: theme.borders.borderRadiusSm,
      pointerEvents: 'auto',
      maxWidth: 400,
    },

    '&&[data-state="open"]': {
      animation: `${fadeInAnimation} 200ms ease-out`,
    },

    '&[data-state="closed"]': {
      animation: `${fadeOutAnimation} 150ms ease-in`,
    },
  });
};

const isSnackbarVertical = (value: string): value is SnackbarVertical => {
  return value === 'top' || value === 'bottom';
};

const isSnackbarHorizontal = (value: string): value is SnackbarHorizontal => {
  return value === 'left' || value === 'center' || value === 'right';
};

const getViewportStyle = (
  theme: Theme,
  vertical: SnackbarVertical,
  horizontal: SnackbarHorizontal,
): React.CSSProperties => {
  const base: React.CSSProperties = {
    position: 'fixed',
    display: 'flex',
    flexDirection: vertical === 'bottom' ? 'column-reverse' : 'column',
    padding: 12,
    gap: 12,
    listStyle: 'none',
    zIndex: theme.options.zIndexBase + 100,
    outline: 'none',
    maxWidth: 400,
    pointerEvents: 'none',
  };

  const verticalStyle: React.CSSProperties = vertical === 'top' ? { top: 0 } : { bottom: 0 };

  const horizontalStyle: React.CSSProperties =
    horizontal === 'center'
      ? { left: '50%', transform: 'translateX(-50%)', alignItems: 'center' }
      : horizontal === 'right'
        ? { right: 0, alignItems: 'flex-end' }
        : { left: 0, alignItems: 'flex-start' };

  return { ...base, ...verticalStyle, ...horizontalStyle };
};

interface SnackBarRootProps {
  snack: SnackbarWithId;
}

const SnackBarRoot = forwardRef<HTMLLIElement, SnackBarRootProps>(function SnackBarRoot(
  { snack }: SnackBarRootProps,
  ref,
) {
  const { theme } = useDesignSystemTheme();

  const memoizedAnalyticsEvents = useMemo(() => [DesignSystemEventProviderAnalyticsEventTypes.OnView], []);
  const eventContext = useDesignSystemEventComponentCallbacks({
    componentType: DesignSystemEventProviderComponentTypes.SnackBar,
    componentId: snack.componentId,
    analyticsEvents: memoizedAnalyticsEvents,
    shouldStartInteraction: false,
  });

  const { elementRef } = useNotifyOnFirstView<HTMLDivElement>({ onView: eventContext.onView });

  // Only triggers when snack is auto-dismissed
  const handleOpenChange = useCallback(
    (open: boolean) => {
      if (!open) {
        // Set snack.open to false because Radix Toast auto-dismiss doesn't set it itself. Necessary for animation to work.
        snackBarManager.closeSnack(snack.id);
      }
    },
    [snack],
  );

  const handleAnimationEnd = useCallback(
    (event: React.AnimationEvent) => {
      if (event.animationName === fadeOutAnimation.name && !snack.open) {
        snackBarManager.deleteSnack(snack.id);
      }
    },
    [snack.id, snack.open],
  );

  const handleClick = useCallback(() => {
    if (snack.closeButton === false) {
      snackBarManager.closeSnack(snack.id);
    }
  }, [snack.id, snack.closeButton]);

  return (
    <Toast.Root
      ref={ref}
      css={getSnackBarRootStyle(theme, snack.backgroundColor, snack.textColor)}
      style={snack.closeButton === false ? { cursor: 'pointer' } : undefined}
      open={snack.open}
      onOpenChange={handleOpenChange}
      duration={snack.autoDismiss}
      onAnimationEndCapture={handleAnimationEnd}
      onClick={snack.closeButton === false ? handleClick : undefined}
      {...addDebugOutlineIfEnabled()}
    >
      <div ref={elementRef}>{snack.content}</div>
      {snack.closeButton !== false && (
        <Toast.Close asChild>
          <Button
            css={getCloseButtonStyles(theme)}
            componentId="design-system.snackbar.close"
            icon={<CloseIcon />}
            aria-label="Close notification"
          />
        </Toast.Close>
      )}
    </Toast.Root>
  );
});

/**
 * SnackBar component
 * Mount this once near the app root to enable snackbar notifications.
 * Multiple instances can be mounted without errors (though typically one is sufficient).
 */
export const SnackBar = (): JSX.Element => {
  const { theme } = useDesignSystemTheme();

  const snacks = useSyncExternalStore(snackBarManager.subscribe, snackBarManager.getSnapshot);

  const snacksByPosition = useMemo(() => {
    const grouped: Record<string, SnackbarWithId[]> = {};

    snacks.forEach((snack) => {
      const key = `${snack.vertical}-${snack.horizontal}`;
      if (!grouped[key]) {
        grouped[key] = [];
      }
      grouped[key].push(snack);
    });

    return grouped;
  }, [snacks]);

  return (
    <>
      {Object.entries(snacksByPosition).map(([key, snacksAtPosition]) => {
        const [vertical, horizontal] = key.split('-');

        if (!isSnackbarVertical(vertical) || !isSnackbarHorizontal(horizontal)) {
          return null;
        }

        return (
          <Toast.Provider key={key}>
            <Toast.Viewport
              className={DU_BOIS_ENABLE_ANIMATION_CLASSNAME}
              style={getViewportStyle(theme, vertical, horizontal)}
              aria-live="polite"
            >
              {snacksAtPosition.map((snack) => (
                <SnackBarRoot key={snack.id} snack={snack} />
              ))}
            </Toast.Viewport>
          </Toast.Provider>
        );
      })}
    </>
  );
};
