export const isValidCustomInputDate = (date: string | undefined, format: string) => {
  if (!date) {
    return false;
  }

  try {
    // Parse the date string using the provided format
    const parsedDate = parse(date, format, new Date());

    // Check if the parsed date is valid
    if (!isValid(parsedDate)) {
      return false;
    }

    // Additional check: ensure the formatted date matches the input
    // This prevents cases like parsing "2023-13-45" which might be invalid
    const formattedDate = formatDateFns(parsedDate, format);
    return formattedDate === date;
  } catch (error) {
    return false;
  }
};
