import { format as formatDateFns, isAfter, isBefore, startOfMonth } from 'date-fns';
import type { KeyboardEvent, ReactNode } from 'react';
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import { Button, ChevronLeftIcon, ChevronRightIcon, Typography, useDesignSystemTheme } from '..';

const MONTHS_PER_YEAR = 12;

export interface MonthPickerGridProps {
  /** The currently selected month as a Date. Year and month components are used. */
  value?: Date;
  /** Callback fired when a month is selected. The Date is set to the 1st of the selected month. */
  onSelect: (date: Date) => void;
  /** Optional: The minimum selectable date. Year and month components are used. */
  min?: Date;
  /** Optional: The maximum selectable date. Year and month components are used. */
  max?: Date;
  /** Optional: Start of a date range. Used to highlight cells between rangeFrom and rangeTo. */
  rangeFrom?: Date;
  /** Optional: End of a date range. Used to highlight cells between rangeFrom and rangeTo. */
  rangeTo?: Date;
  /** Optional: Receives the cell date and the full default button element. The caller can wrap it
   * (e.g., add a dot indicator) or replace it entirely (e.g., to apply custom `disabled` logic). */
  renderCellContent?: (date: Date, defaultContent: ReactNode) => ReactNode;
  /** Optional: Additional predicate to disable individual month cells beyond `min`/`max`. */
  isDateDisabled?: (date: Date) => boolean;
}

interface MonthCellProps {
  index: number;
  label: string;
  displayYear: number;
  selected: boolean;
  disabled: boolean;
  rangeFrom: Date | undefined;
  rangeTo: Date | undefined;
  focusedIndex: number;
  onSelect: (monthIndex: number) => void;
  onKeyDown: (event: KeyboardEvent<HTMLButtonElement>, monthIndex: number) => void;
  onFocus: (monthIndex: number) => void;
  renderCellContent?: (date: Date, defaultContent: ReactNode) => ReactNode;
}

function getGridCellCss(
  theme: ReturnType<typeof useDesignSystemTheme>['theme'],
  isRangeStart: boolean,
  isRangeEnd: boolean,
  isRangeMiddle: boolean,
  index: number,
) {
  return {
    padding: 0,
    backgroundColor: isRangeMiddle ? theme.colors.actionTertiaryBackgroundPress : 'transparent',
    ...(isRangeStart && {
      borderTopLeftRadius: theme.general.borderRadiusBase,
      borderBottomLeftRadius: theme.general.borderRadiusBase,
      borderTopRightRadius: 0,
      borderBottomRightRadius: 0,
      backgroundColor: theme.colors.actionTertiaryBackgroundPress,
    }),
    ...(isRangeEnd && {
      borderTopRightRadius: theme.general.borderRadiusBase,
      borderBottomRightRadius: theme.general.borderRadiusBase,
      borderTopLeftRadius: 0,
      borderBottomLeftRadius: 0,
      backgroundColor: theme.colors.actionTertiaryBackgroundPress,
    }),
    ...(isRangeStart &&
      isRangeEnd && {
        borderRadius: theme.general.borderRadiusBase,
      }),
    // Round left edge for first column cells in range
    ...(isRangeMiddle &&
      index % 4 === 0 && {
        borderTopLeftRadius: theme.general.borderRadiusBase,
        borderBottomLeftRadius: theme.general.borderRadiusBase,
      }),
    // Round right edge for last column cells in range
    ...(isRangeMiddle &&
      index % 4 === 3 && {
        borderTopRightRadius: theme.general.borderRadiusBase,
        borderBottomRightRadius: theme.general.borderRadiusBase,
      }),
  };
}

function getButtonCss(
  theme: ReturnType<typeof useDesignSystemTheme>['theme'],
  selected: boolean,
  isRangeStart: boolean,
  isRangeEnd: boolean,
  isCurrentMonth: boolean,
) {
  return {
    width: '100%',
    // DS Button's importantify wraps borderColor with !important, so we must override here.
    // borderWidth is always 2px (matching DayPicker's --rdp-outline) so focus doesn't cause layout shift.
    borderColor: 'transparent !important',
    borderWidth: '2px !important',
    boxShadow: 'none !important',
    '&[disabled]': {
      borderColor: 'transparent !important',
    },
    fontWeight: isCurrentMonth ? 'bold' : 'normal',
    // Non-selected focused: DayPicker shows light blue bg + single inner border ring (no outer outline).
    // Selected+focused gets the 2-ring style (inner + outer with gap) via the selected override below.
    // borderWidth ensures the 2px ring matches DayPicker's --rdp-outline (2px solid accent).
    '&:focus-visible': {
      backgroundColor: `${theme.colors.actionTertiaryBackgroundPress} !important`,
      borderColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
      outlineColor: 'transparent !important',
    },
    // Use the exact same colors as DayPicker for selected/range start/end cells.
    // Manually applying actionPrimaryBackground* + #fff text ensures consistent
    // appearance across light and dark themes without relying on Button type='primary'.
    ...((selected || isRangeStart || isRangeEnd) && {
      backgroundColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
      color: '#fff !important',
      '&:hover': {
        backgroundColor: `${theme.colors.actionPrimaryBackgroundHover} !important`,
        color: '#fff !important',
        // Keep border transparent on hover — DS Button shows a border on hover by default
        borderColor: 'transparent !important',
      },
      '&:active': {
        backgroundColor: `${theme.colors.actionPrimaryBackgroundPress} !important`,
        color: '#fff !important',
      },
      // Keyboard focus on selected cell: DayPicker's .button:focus-visible:not([disabled]) has
      // higher specificity than .day_selected, so selected+focused shows the hover (light blue)
      // background with dark text, inner border ring, and outer outline ring.
      '&:focus-visible': {
        backgroundColor: `${theme.colors.actionTertiaryBackgroundPress} !important`,
        color: 'inherit !important',
        borderColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
        outlineColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
        outlineOffset: '2px !important',
      },
    }),
    ...(!(selected || isRangeStart || isRangeEnd) && {
      backgroundColor: 'transparent !important',
      '&:hover:not([disabled])': {
        backgroundColor: `${theme.colors.actionTertiaryBackgroundPress} !important`,
        color: 'inherit !important',
        // Keep border transparent on hover — DS Button shows a border on hover by default
        borderColor: 'transparent !important',
      },
    }),
    // Match button border-radius to gridcell container for range start/end
    ...(isRangeStart &&
      !isRangeEnd && {
        borderTopRightRadius: 0,
        borderBottomRightRadius: 0,
      }),
    ...(isRangeEnd &&
      !isRangeStart && {
        borderTopLeftRadius: 0,
        borderBottomLeftRadius: 0,
      }),
  };
}

function MonthCell({
  index,
  label,
  displayYear,
  selected,
  disabled,
  rangeFrom,
  rangeTo,
  focusedIndex,
  onSelect,
  onKeyDown,
  onFocus,
  renderCellContent,
}: MonthCellProps): JSX.Element {
  const { theme } = useDesignSystemTheme();
  const now = new Date();
  const isCurrentMonth = displayYear === now.getFullYear() && index === now.getMonth();
  const cellValue = displayYear * 12 + index;
  const rangeFromValue = rangeFrom !== undefined ? rangeFrom.getFullYear() * 12 + rangeFrom.getMonth() : undefined;
  const rangeToValue = rangeTo !== undefined ? rangeTo.getFullYear() * 12 + rangeTo.getMonth() : undefined;
  const inRange =
    rangeFromValue !== undefined &&
    rangeToValue !== undefined &&
    cellValue >= rangeFromValue &&
    cellValue <= rangeToValue;
  const isRangeStart = rangeFromValue !== undefined && cellValue === rangeFromValue;
  const isRangeEnd = rangeToValue !== undefined && cellValue === rangeToValue;
  const isRangeMiddle = inRange && !isRangeStart && !isRangeEnd;
  const defaultButton = (
    <Button
      componentId="datepicker-month-grid-cell"
      aria-label={`${label} ${displayYear}`}
      data-selected={selected || undefined}
      aria-current={isCurrentMonth ? 'date' : undefined}
      disabled={disabled}
      tabIndex={index === focusedIndex ? 0 : -1}
      onClick={() => !disabled && onSelect(index)}
      onKeyDown={(e) => onKeyDown(e, index)}
      onFocus={() => onFocus(index)}
      css={getButtonCss(theme, selected, isRangeStart, isRangeEnd, isCurrentMonth)}
    >
      {label}
    </Button>
  );
  return (
    <div key={index} role="gridcell" css={getGridCellCss(theme, isRangeStart, isRangeEnd, isRangeMiddle, index)}>
      {renderCellContent ? renderCellContent(new Date(displayYear, index, 1), defaultButton) : defaultButton}
    </div>
  );
}

/**
 * MonthPickerGrid renders a 4x3 grid of month names for a given year with year navigation.
 * It is used inside the DatePicker when `granularity='month'` is set.
 */
export function MonthPickerGrid({
  value,
  onSelect,
  min,
  max,
  rangeFrom,
  rangeTo,
  renderCellContent,
  isDateDisabled,
}: MonthPickerGridProps): JSX.Element {
  const { theme } = useDesignSystemTheme();

  const selectedYear = value?.getFullYear();
  const selectedMonth = value?.getMonth();

  const [displayYear, setDisplayYear] = useState(selectedYear ?? new Date().getFullYear());

  const months = useMemo(() => {
    const result: { index: number; label: string }[] = [];
    for (let i = 0; i < MONTHS_PER_YEAR; i++) {
      result.push({
        index: i,
        label: formatDateFns(new Date(displayYear, i, 1), 'MMM'),
      });
    }
    return result;
  }, [displayYear]);

  const isDisabled = useCallback(
    (monthIndex: number) => {
      const cellDate = new Date(displayYear, monthIndex, 1);
      if (min !== undefined && isBefore(cellDate, startOfMonth(min))) return true;
      if (max !== undefined && isAfter(cellDate, startOfMonth(max))) return true;
      if (isDateDisabled?.(cellDate)) return true;
      return false;
    },
    [displayYear, min, max, isDateDisabled],
  );

  // Roving tabindex: track which grid cell is the "active" tabbable one.
  // This ensures exactly one grid cell always has tabIndex=0 so Tab can reach the grid.
  const getInitialFocusIndex = useCallback(() => {
    if (selectedYear !== undefined && selectedMonth !== undefined && displayYear === selectedYear) {
      if (!isDisabled(selectedMonth)) return selectedMonth;
    }
    // Fall back to first non-disabled cell so keyboard navigation always has a starting point
    const firstEnabled = Array.from({ length: MONTHS_PER_YEAR }, (_, i) => i).findIndex((m) => !isDisabled(m));
    return firstEnabled >= 0 ? firstEnabled : 0;
  }, [selectedYear, selectedMonth, displayYear, isDisabled]);

  const [focusedIndex, setFocusedIndex] = useState(getInitialFocusIndex);

  // Update focused index when display year changes (e.g. after prev/next navigation)
  useEffect(() => {
    setFocusedIndex(getInitialFocusIndex());
  }, [displayYear, selectedYear, selectedMonth, getInitialFocusIndex]);

  const handlePrevYear = useCallback(() => {
    setDisplayYear((prev) => prev - 1);
  }, []);

  const handleNextYear = useCallback(() => {
    setDisplayYear((prev) => prev + 1);
  }, []);

  const handleSelectMonth = useCallback(
    (monthIndex: number) => {
      onSelect(new Date(displayYear, monthIndex, 1));
    },
    [displayYear, onSelect],
  );

  const gridRef = useRef<HTMLDivElement>(null);

  const focusCellAtIndex = useCallback((nextIndex: number) => {
    const grid = gridRef.current;
    if (grid) {
      const buttons = grid.querySelectorAll<HTMLButtonElement>('[role="gridcell"] button');
      buttons[nextIndex]?.focus();
    }
  }, []);

  const handleKeyDown = useCallback((event: KeyboardEvent<HTMLButtonElement>, monthIndex: number) => {
    let nextIndex = monthIndex;
    switch (event.key) {
      case 'ArrowRight':
        event.preventDefault();
        if (monthIndex >= MONTHS_PER_YEAR - 1) {
          // At the end of the grid — navigate to next year, focus first cell
          setDisplayYear((prev) => prev + 1);
          nextIndex = 0;
        } else {
          nextIndex = monthIndex + 1;
        }
        break;
      case 'ArrowLeft':
        event.preventDefault();
        if (monthIndex <= 0) {
          // At the start of the grid — navigate to previous year, focus last cell
          setDisplayYear((prev) => prev - 1);
          nextIndex = MONTHS_PER_YEAR - 1;
        } else {
          nextIndex = monthIndex - 1;
        }
        break;
      case 'ArrowDown':
        event.preventDefault();
        if (monthIndex + 4 >= MONTHS_PER_YEAR) {
          // At the bottom of the grid — navigate to next year, keep column position
          setDisplayYear((prev) => prev + 1);
          nextIndex = monthIndex % 4; // keep same column, first row
        } else {
          nextIndex = monthIndex + 4;
        }
        break;
      case 'ArrowUp':
        event.preventDefault();
        if (monthIndex - 4 < 0) {
          // At the top of the grid — navigate to previous year, keep column position
          setDisplayYear((prev) => prev - 1);
          nextIndex = MONTHS_PER_YEAR - 4 + (monthIndex % 4); // keep same column, last row
        } else {
          nextIndex = monthIndex - 4;
        }
        break;
      // Enter and Space are handled by the DS Button's onClick — no need to handle here
      default:
        return;
    }
    setFocusedIndex(nextIndex);
  }, []);

  // Navigation buttons are never disabled — users should always be able to browse pages.
  // Only individual grid cells are disabled by min/max constraints.
  const isPrevDisabled = false;
  const isNextDisabled = false;

  // Focus the active grid cell whenever focusedIndex changes (covers both initial mount
  // and post-navigation focus after arrow key presses or month page changes).
  useEffect(() => {
    focusCellAtIndex(focusedIndex);
  }, [focusedIndex, focusCellAtIndex]);

  return (
    <div style={{ padding: theme.spacing.xs, minWidth: 225 }}>
      {/* Navigation header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: `0 ${theme.spacing.xs}px`,
          marginBottom: theme.spacing.xs,
        }}
      >
        <Button
          componentId="datepicker-month-grid-prev"
          aria-label="Previous year"
          icon={<ChevronLeftIcon />}
          onClick={handlePrevYear}
          disabled={isPrevDisabled}
          size="small"
        />
        <Typography.Text bold aria-live="polite">
          {displayYear}
        </Typography.Text>
        <Button
          componentId="datepicker-month-grid-next"
          aria-label="Next year"
          icon={<ChevronRightIcon />}
          onClick={handleNextYear}
          disabled={isNextDisabled}
          size="small"
        />
      </div>

      {/* Month grid */}
      <div
        ref={gridRef}
        role="grid"
        aria-label="Month picker"
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
        }}
      >
        {months.map(({ index, label }) => (
          <MonthCell
            key={index}
            index={index}
            label={label}
            displayYear={displayYear}
            selected={displayYear === selectedYear && index === selectedMonth}
            disabled={isDisabled(index)}
            rangeFrom={rangeFrom}
            rangeTo={rangeTo}
            focusedIndex={focusedIndex}
            onSelect={handleSelectMonth}
            onKeyDown={handleKeyDown}
            onFocus={setFocusedIndex}
            renderCellContent={renderCellContent}
          />
        ))}
      </div>
    </div>
  );
}
