// TODO(GP): Add this to common spacing vars; I didn't want to make a decision on the value right now,
// so copied it from `Button`.
const SMALL_BUTTON_HEIGHT = 24;

function getSegmentedControlGroupEmotionStyles(
  clsPrefix: string,
  theme: Theme,
  spaced: boolean = false,
  useSegmentedSliderStyle: boolean = false,
) {
  const classGroup = `.${clsPrefix}-radio-group`;
  const classSmallGroup = `.${clsPrefix}-radio-group-small`;
  const classButtonWrapper = `.${clsPrefix}-radio-button-wrapper`;

  const styles: CSSObject = {
    display: 'flex',
    maxWidth: '100%',
    [`&${classGroup}`]: spaced ? { display: 'flex', gap: 8, flexWrap: 'wrap' } : {},

    [`&${classSmallGroup} ${classButtonWrapper}`]: {
      padding: '0 12px',
    },
  };

  const sliderStyles: CSSObject = {
    height: 'min-content',
    width: 'min-content',
    background: theme.colors.backgroundSecondary,
    borderRadius: theme.borders.borderRadiusSm,
    display: 'flex',
    gap: theme.spacing.xs,
    maxWidth: '100%',
    overflow: 'auto',
  };

  const importantStyles = importantify(useSegmentedSliderStyle && !spaced ? sliderStyles : styles);

  return css(importantStyles);
}

function getSegmentedControlButtonEmotionStyles(
  clsPrefix: string,
  theme: Theme,
  size: ButtonSize,
  spaced: boolean = false,
  onlyIcon: boolean,
  useSegmentedSliderStyle: boolean = false,
) {
  const classWrapperChecked = `.${clsPrefix}-radio-button-wrapper-checked`;
  const classWrapper = `.${clsPrefix}-radio-button-wrapper`;
  const classWrapperDisabled = `.${clsPrefix}-radio-button-wrapper-disabled`;
  const classButton = `.${clsPrefix}-radio-button`;
  const classIcon = `.${theme.general.iconfontCssPrefix}`;

  // Note: Ant radio button uses a 1px-wide `before` pseudo-element to recreate the left border of the button.
  // This is because the actual left border is disabled to avoid a double-border effect with the adjacent button's
  // right border.
  // We must override the background colour of this pseudo-border to be the same as the real border above.

  const styles: CSSObject = {
    backgroundColor: theme.colors.actionDefaultBackgroundDefault,
    borderColor: theme.colors.actionDefaultBorderDefault,
    color: theme.colors.actionDefaultTextDefault,
    boxShadow: theme.shadows.xs,

    // This handles the left border of the button when they're adjacent
    '::before': {
      display: spaced ? 'none' : 'block',
      backgroundColor: theme.colors.actionDefaultBorderDefault,
    },

    '&:hover': {
      backgroundColor: theme.colors.actionDefaultBackgroundHover,
      borderColor: theme.colors.actionDefaultBorderHover,
      color: theme.colors.actionDefaultTextHover,

      '::before': {
        backgroundColor: theme.colors.actionDefaultBorderHover,
      },

      // Also target the same pseudo-element on the next sibling, because this is used to create the right border
      [`& + ${classWrapper}::before`]: {
        backgroundColor: theme.colors.actionDefaultBorderPress,
      },
    },

    '&:active': {
      backgroundColor: theme.colors.actionTertiaryBackgroundPress,
      borderColor: theme.colors.actionDefaultBorderPress,
      color: theme.colors.actionTertiaryTextPress,
    },

    [`&${classWrapperChecked}`]: {
      backgroundColor: theme.colors.actionTertiaryBackgroundPress,
      borderColor: theme.colors.actionDefaultBorderPress,
      color: theme.colors.actionTertiaryTextPress,

      '::before': {
        backgroundColor: theme.colors.actionDefaultBorderPress,
      },

      [`& + ${classWrapper}::before`]: {
        backgroundColor: theme.colors.actionDefaultBorderPress,
      },
    },

    [`&${classWrapperChecked}:focus-within`]: {
      '::before': {
        width: 0,
      },
    },

    [`&${classWrapper}`]: {
      padding: size === 'middle' ? `0 16px` : '0 8px',
      display: 'inline-flex',
      ...(onlyIcon
        ? {
            '& > span': {
              display: 'inline-flex',
            },
          }
        : {}),
      verticalAlign: 'middle',
      flexShrink: 1,
      textOverflow: 'ellipsis',
      whiteSpace: 'nowrap',

      '&:first-of-type': {
        borderTopLeftRadius: theme.borders.borderRadiusSm,
        borderBottomLeftRadius: theme.borders.borderRadiusSm,
      },
      '&:last-of-type': {
        borderTopRightRadius: theme.borders.borderRadiusSm,
        borderBottomRightRadius: theme.borders.borderRadiusSm,
      },
      ...(spaced
        ? {
            borderWidth: 1,
            borderRadius: theme.borders.borderRadiusSm,
          }
        : {}),

      '&:focus-within': {
        outlineStyle: 'solid',
        outlineWidth: '2px',
        outlineOffset: '-2px',
        outlineColor: theme.colors.actionDefaultBorderFocus,
      },

      'span:last-of-type': {
        textOverflow: 'ellipsis',
        overflow: 'hidden',
        whiteSpace: 'nowrap',
      },
    },

    [`&${classWrapper}, ${classButton}`]: {
      height: size === 'middle' ? theme.general.heightSm : SMALL_BUTTON_HEIGHT,
      lineHeight: theme.typography.lineHeightBase,
      alignItems: 'center',
    },

    [`&${classWrapperDisabled}, &${classWrapperDisabled} + ${classWrapperDisabled}`]: {
      color: theme.colors.actionDisabledText,
      backgroundColor: 'transparent',
      borderColor: theme.colors.actionDisabledBorder,

      '&:hover': {
        color: theme.colors.actionDisabledText,
        borderColor: theme.colors.actionDisabledBorder,
        backgroundColor: 'transparent',
      },
      '&:active': {
        color: theme.colors.actionDisabledText,
        borderColor: theme.colors.actionDisabledBorder,
        backgroundColor: 'transparent',
      },

      '::before': {
        backgroundColor: theme.colors.actionDisabledBorder,
      },

      [`&${classWrapperChecked}`]: {
        borderColor: theme.colors.actionDefaultBorderPress,
        '::before': {
          backgroundColor: theme.colors.actionDefaultBorderPress,
        },
      },
      [`&${classWrapperChecked} + ${classWrapper}`]: {
        '::before': {
          backgroundColor: theme.colors.actionDefaultBorderPress,
        },
      },
    },

    ...getAnimationCss(theme.options.enableAnimation),
  };

  const sliderStyles: CSSObject = {
    minWidth: 'fit-content',
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    whiteSpace: 'nowrap',
    border: 'none',
    display: 'inline-flex',
    alignItems: 'center',
    color: theme.colors.textSecondary,
    borderRadius: theme.borders.borderRadiusSm,
    backgroundColor: 'transparent',

    '::before': { display: 'none' },

    '&:hover': {
      backgroundColor: theme.colors.tableRowHover,
    },

    [`&${classWrapper}`]: {
      padding: size === 'middle' ? (onlyIcon ? `0 ${theme.spacing.sm}px` : `0 12px`) : `0 ${theme.spacing.sm}px`,
      verticalAlign: 'middle',

      flexShrink: 1,
      textOverflow: 'ellipsis',
      whiteSpace: 'nowrap',

      '& > span:last-of-type': {
        display: 'inline-block',
        textOverflow: 'ellipsis',
        overflow: 'hidden',
        whiteSpace: 'nowrap',

        '& > *': {
          display: 'flex',
          alignItems: 'center',
        },
      },
      '& > span': {
        display: 'inline-flex',
      },
    },

    [`&${classWrapper}, ${classButton}`]: {
      height: size === 'middle' ? theme.general.heightSm : SMALL_BUTTON_HEIGHT,
      lineHeight: theme.typography.lineHeightBase,
      alignItems: 'center',
    },

    [`&${classWrapperChecked}`]: {
      color: theme.colors.actionDefaultTextDefault,
      [`${classIcon}`]: {
        color: theme.colors.textSecondary,
      },
      backgroundColor: theme.colors.backgroundPrimary,
      boxShadow: `inset 0 0 0 1px ${theme.colors.actionDefaultBorderDefault}, ${theme.shadows.sm}`,
    },

    [`&${classWrapperDisabled}, &${classWrapperDisabled} + ${classWrapperDisabled}`]: {
      color: theme.colors.actionDisabledText,
      backgroundColor: 'transparent',
    },

    ...getAnimationCss(theme.options.enableAnimation),
  };

  const importantStyles = importantify(useSegmentedSliderStyle && !spaced ? sliderStyles : styles);

  return css(importantStyles);
}

const SegmentedControlGroupContext = createContext<{
  size: ButtonSize;
  spaced?: boolean;
  useSegmentedSliderStyle?: boolean;
}>({
  size: 'middle',
  spaced: false,
  useSegmentedSliderStyle: false,
});
export interface SegmentedControlButtonProps
  extends
    Omit<RadioButtonProps, 'optionType' | 'buttonStyle' | 'prefixCls' | 'skipGroup' | 'title'>,
    DangerouslySetAntdProps<RadioButtonProps>,
    HTMLDataAttributes {
  icon?: React.ReactNode;
  /**
   * Title text to display when hovering over the button using the browser's native tooltip.
   */
  title?: string;
}

export const SegmentedControlButton = forwardRef<HTMLButtonElement, SegmentedControlButtonProps>(
  function SegmentedControlButton(
    { dangerouslySetAntdProps, title, ...props }: SegmentedControlButtonProps,
    ref,
  ): JSX.Element {
    const { classNamePrefix, theme } = useDesignSystemTheme();
    const { size, spaced, useSegmentedSliderStyle } = useContext(SegmentedControlGroupContext);
    const buttonRef = useRef<HTMLButtonElement>(null);
    useImperativeHandle(ref, () => buttonRef.current as HTMLButtonElement);
    // Check if this is icon-only: either using icon prop without children,
    // or icon prop with children that contain no text (e.g., icon prop with a wrapper component)
    const childrenHasText = React.Children.toArray(props.children).some(
      (child) => typeof child === 'string' || typeof child === 'number',
    );
    const onlyIcon =
      Boolean(props.icon && !props.children) || Boolean(props.icon && props.children && !childrenHasText);

    const getLabelFromChildren = useCallback((): string => {
      let label = '';

      React.Children.map(props.children, (child) => {
        if (typeof child === 'string') {
          label += child;
        }
      });

      return label;
    }, [props.children]);

    useEffect(() => {
      if (buttonRef.current) {
        // Using `as any` because Antd uses a `Checkbox` type that's not exported
        const labelParent = (buttonRef.current as any).input.closest('label');

        if (labelParent) {
          // Set title: use custom title if provided, otherwise use button text
          const titleText = title !== undefined ? title : getLabelFromChildren();
          if (titleText) {
            labelParent.setAttribute('title', titleText);
          }

          const labelWidth = labelParent.scrollWidth;

          const threshold = size === 'small' ? 58 : 68;
          if (labelWidth > threshold) {
            labelParent.style.setProperty('min-width', `${threshold}px`, 'important');
          }
        }
      }
    }, [buttonRef, getLabelFromChildren, size, title]);

    return (
      <DesignSystemAntDConfigProvider>
        <AntDRadio.Button
          css={getSegmentedControlButtonEmotionStyles(
            classNamePrefix,
            theme,
            size,
            spaced,
            onlyIcon,
            useSegmentedSliderStyle,
          )}
          {...props}
          {...dangerouslySetAntdProps}
          ref={buttonRef}
        >
          {props.icon ? (
            <div css={{ display: 'inline-flex', alignItems: 'center', gap: theme.spacing.xs }}>
              {props.icon}
              {props.children ? (
                <span css={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {props.children}
                </span>
              ) : (
                props.children
              )}
            </div>
          ) : (
            props.children
          )}
        </AntDRadio.Button>
      </DesignSystemAntDConfigProvider>
    );
  },
);

export interface SegmentedControlGroupProps
  extends
    Omit<RadioGroupProps, 'size'>,
    DangerouslySetAntdProps<RadioGroupProps>,
    HTMLDataAttributes,
    AnalyticsEventValueChangeNoPiiFlagProps<
      DesignSystemEventProviderAnalyticsEventTypes.OnValueChange | DesignSystemEventProviderAnalyticsEventTypes.OnView
    > {
  size?: ButtonSize;
  spaced?: boolean;
  name: string;
  newStyleFlagOverride?: boolean;
  'aria-labelledby'?: string;
}

export const SegmentedControlGroup = forwardRef<HTMLDivElement, SegmentedControlGroupProps>(
  function SegmentedControlGroup(
    {
      dangerouslySetAntdProps,
      size = 'middle',
      spaced = false,
      onChange,
      componentId,
      analyticsEvents,
      valueHasNoPii,
      newStyleFlagOverride,
      ...props
    }: SegmentedControlGroupProps,
    ref,
  ): JSX.Element {
    const emitOnView = safex('databricks.fe.observability.defaultComponentView.segmentedControlGroup', false);
    const { classNamePrefix, theme } = useDesignSystemTheme();
    const useSegmentedSliderStyle =
      newStyleFlagOverride ?? safex('databricks.fe.designsystem.useNewSegmentedControlStyles', false);
    const uniqueId = useUniqueId();
    const internalRef = useRef<HTMLDivElement>();
    useImperativeHandle(ref, () => internalRef.current as HTMLDivElement);
    const memoizedAnalyticsEvents = useMemo(
      () =>
        analyticsEvents ??
        (emitOnView
          ? [
              DesignSystemEventProviderAnalyticsEventTypes.OnValueChange,
              DesignSystemEventProviderAnalyticsEventTypes.OnView,
            ]
          : [DesignSystemEventProviderAnalyticsEventTypes.OnValueChange]),
      [analyticsEvents, emitOnView],
    );
    const eventContext = useDesignSystemEventComponentCallbacks({
      componentType: DesignSystemEventProviderComponentTypes.SegmentedControlGroup,
      componentId,
      analyticsEvents: memoizedAnalyticsEvents,
      valueHasNoPii,
    });
    const { elementRef: segmentedControlGroupRef } = useNotifyOnFirstView<HTMLDivElement>({
      onView: eventContext.onView,
      value: props.value ?? props.defaultValue,
    });

    const mergedRef = useMergeRefs<HTMLDivElement>([internalRef as Ref<HTMLDivElement>, segmentedControlGroupRef]);

    const onChangeWrapper = useCallback(
      (e: RadioChangeEvent) => {
        eventContext.onValueChange(e.target.value);

        onChange?.(e);
      },
      [eventContext, onChange],
    );

    const ariaLabelledby = props['aria-labelledby'];

    // A11y helper (FIT-1649): Effect helping to set the aria-labelledby attribute on the radio group if it is not provided
    useEffect(() => {
      if (ariaLabelledby) {
        return;
      }

      if (props.id) {
        // look for the label of the group pointing to the id
        const label = document.querySelector(`label[for="${props.id}"]`);
        if (label) {
          // If the label already has an id, map the radio group to it
          if (label.hasAttribute('id')) {
            internalRef.current?.setAttribute('aria-labelledby', label.getAttribute('id') ?? '');
          } else {
            label.setAttribute('id', `${props.id}${uniqueId}-label`);
            internalRef.current?.setAttribute('aria-labelledby', `${props.id}${uniqueId}-label`);
          }
        }
      }
    }, [ariaLabelledby, props.id, uniqueId]);

    return (
      <DesignSystemAntDConfigProvider>
        <SegmentedControlGroupContext.Provider value={{ size, spaced, useSegmentedSliderStyle }}>
          <AntDRadio.Group
            {...addDebugOutlineIfEnabled()}
            {...props}
            css={getSegmentedControlGroupEmotionStyles(classNamePrefix, theme, spaced, useSegmentedSliderStyle)}
            // @ts-expect-error - role is not a valid prop for RadioGroup in Antd but it applies it correctly to the group
            role="radiogroup"
            onChange={onChangeWrapper}
            {...dangerouslySetAntdProps}
            ref={mergedRef}
            {...eventContext.dataComponentProps}
          />
        </SegmentedControlGroupContext.Provider>
      </DesignSystemAntDConfigProvider>
    );
  },
);
