import type { CSSObject } from '@emotion/react';
import { css } from '@emotion/react';
import type { AlertProps as AntDAlertProps } from 'antd';
import { Alert as AntDAlert } from 'antd';
import cx from 'classnames';
import { useEffect, useMemo, useRef, useState } from 'react';

import type { Theme } from '../../theme';
import type { ButtonProps } from '../Button';
import { Button } from '../Button';
import {
  DesignSystemEventProviderAnalyticsEventTypes,
  DesignSystemEventProviderComponentTypes,
  useDesignSystemEventComponentCallbacks,
  DesignSystemEventProviderComponentSubTypeMap,
} from '../DesignSystemEventProvider';
import { DesignSystemAntDConfigProvider, getAnimationCss } from '../DesignSystemProvider';
import { useDesignSystemTheme } from '../Hooks';
import { ChevronDownIcon, ChevronRightIcon, CloseSmallIcon } from '../Icon';
import { SeverityIcon } from '../Icon/iconMap';
import { Modal } from '../Modal';
import { Typography } from '../Typography';
import type { AnalyticsEventProps, DangerouslySetAntdProps, HTMLDataAttributes } from '../types';
import { useNotifyOnFirstView } from '../utils';
import { addDebugOutlineIfEnabled } from '../utils/debug';
import { useStableUuidV4 } from '../utils/useStableUuidV4';

export type AlertType = NonNullable<AntDAlertProps['type']>;

export interface AlertProps
  extends
    Omit<AntDAlertProps, 'closeText' | 'showIcon' | 'type' | 'icon'>,
    HTMLDataAttributes,
    DangerouslySetAntdProps<AntDAlertProps>,
    AnalyticsEventProps<DesignSystemEventProviderAnalyticsEventTypes.OnView> {
  type: AlertType;
  closeIconLabel?: string;
  /**
   * @deprecated Use CEP-governed banners instead. go/banner/create go/getabanner go/banner
   */
  banner?: boolean;
  /**
   * @deprecated Please use `actions` instead.
   */
  action?: AntDAlertProps['action'];
  /** Array of button props to render as footer actions. All buttons will be rendered as small size. */
  actions?: Omit<ButtonProps, 'size' | 'type'>[];
  /** Force actions to be rendered beneath the description. */
  forceVerticalActionsPlacement?: boolean;
  /**
   * When true (and `forceVerticalActionsPlacement` is false), multiple `actions` render in the top
   * horizontal action slot instead of stacking under the description.
   */
  forceHorizontalActionsPlacement?: boolean;
  /** When true, the description body (and vertical actions, if any) can be collapsed via a chevron control. */
  collapsible?: boolean;
  /** Initial expanded state when `collapsible` is true. Defaults to true. */
  defaultExpanded?: boolean;
  /** Accessible label for the expand control when collapsed. Defaults to "Expand alert details". */
  expandToggleAriaLabel?: string;
  /** Accessible label for the collapse control when expanded. Defaults to "Collapse alert details". */
  collapseToggleAriaLabel?: string;
  /** Content to display in a modal when "Show details" is clicked */
  showMoreContent?: React.ReactNode;
  /** Text for the "Show details" link. Defaults to "Show details" */
  showMoreText?: string;
  /** Text for "Show details" modal title. Defaults to "Details" */
  showMoreModalTitle?: string;
  size?: 'small' | 'large';
}

export const Alert: React.FC<React.PropsWithChildren<AlertProps>> = ({
  componentId,
  analyticsEvents = [DesignSystemEventProviderAnalyticsEventTypes.OnView],
  dangerouslySetAntdProps,
  closable = true,
  closeIconLabel = 'Close alert',
  onClose,
  actions,
  showMoreContent,
  showMoreText = 'Show details',
  showMoreModalTitle = 'Details',
  forceVerticalActionsPlacement = false,
  forceHorizontalActionsPlacement = false,
  collapsible = false,
  defaultExpanded = true,
  expandToggleAriaLabel = 'Expand alert details',
  collapseToggleAriaLabel = 'Collapse alert details',
  size = 'large',
  ...props
}) => {
  const { theme, getPrefixedClassName } = useDesignSystemTheme();
  const memoizedAnalyticsEvents = useMemo(() => analyticsEvents, [analyticsEvents]);
  const eventContext = useDesignSystemEventComponentCallbacks({
    componentType: DesignSystemEventProviderComponentTypes.Alert,
    componentId,
    componentSubType: DesignSystemEventProviderComponentSubTypeMap[props.type],
    analyticsEvents: memoizedAnalyticsEvents,
  });
  const closeButtonEventContext = useDesignSystemEventComponentCallbacks({
    componentType: DesignSystemEventProviderComponentTypes.Button,
    componentId: componentId ? `${componentId}.close` : 'codegen_design_system_src_design_system_alert_alert.tsx_50',
    analyticsEvents: [DesignSystemEventProviderAnalyticsEventTypes.OnClick],
  });
  const { elementRef } = useNotifyOnFirstView<HTMLSpanElement>({ onView: eventContext.onView });
  const clsPrefix = getPrefixedClassName('alert');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);
  const descriptionRegionId = useStableUuidV4();

  const mergedProps: AntDAlertProps & { type: AlertType } = {
    ...props,
    type: props.type || 'error',
    showIcon: true,
    closable,
  };

  const closeIconRef = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    if (closeIconRef.current) {
      closeIconRef.current.removeAttribute('aria-label');
      closeIconRef.current.closest('button')?.setAttribute('aria-label', closeIconLabel);
    }
  }, [mergedProps.closable, closeIconLabel, closeIconRef]);

  const onCloseWrapper: React.MouseEventHandler<HTMLButtonElement> = (e) => {
    closeButtonEventContext.onClick(e);
    onClose?.(e);
  };

  const memoizedActions = useMemo(() => {
    if (!actions?.length) return null;
    return actions.map((action, index) => <Button key={index} size="small" {...action} />);
  }, [actions]);

  const actionCount = actions?.length ?? 0;
  const placeActionsHorizontally =
    actionCount > 0 && !forceVerticalActionsPlacement && (actionCount === 1 || forceHorizontalActionsPlacement);

  const horizontalActionsNode =
    memoizedActions && placeActionsHorizontally ? (
      <div
        css={{
          display: 'flex',
          flexDirection: 'row',
          flexWrap: 'wrap',
          gap: theme.spacing.sm,
          alignItems: 'center',
          justifyContent: 'flex-end',
          flexShrink: 0,
          marginInlineStart: 'auto',
        }}
      >
        {memoizedActions}
      </div>
    ) : null;

  const hasDescription = props.description != null || Boolean(showMoreContent);

  // Put horizontal `actions` inside `message` so the description body spans the full content width
  // and flows beneath the buttons (antd's `action` slot keeps description in a narrow column beside actions).
  // Reserve ~one short status title line (e.g. "Gateway starting") before sharing a row with actions;
  // when the row is too narrow, actions wrap below via flex-wrap instead of squeezing the title.
  const messageWithHorizontalActions =
    horizontalActionsNode && !mergedProps.action ? (
      <div
        css={{
          display: 'flex',
          flexDirection: 'row',
          flexWrap: actionCount > 1 ? 'wrap' : 'nowrap',
          alignItems: hasDescription ? 'flex-start' : 'center',
          gap: theme.spacing.md,
          justifyContent: 'flex-start',
          width: '100%',
        }}
      >
        <div
          css={{
            flex: '1 1 auto',
            maxWidth: '100%',
          }}
        >
          {mergedProps.message}
        </div>
        {horizontalActionsNode}
      </div>
    ) : null;
  const hasVerticalActions = memoizedActions != null && !placeActionsHorizontally;
  const showCollapseToggle = collapsible && (hasDescription || hasVerticalActions);
  const hasDescriptionSlotContent = hasDescription || hasVerticalActions || showCollapseToggle;

  const descriptionTextNode = hasDescription ? (
    <div css={{ overflowWrap: 'anywhere', wordBreak: 'break-word' }}>
      {props.description}{' '}
      {showMoreContent && (
        <Typography.Link
          href="#"
          componentId={componentId ? `${componentId}.show_more` : 'alert.show_more'}
          onClick={(e) => {
            e.preventDefault();
            setIsModalOpen(true);
          }}
        >
          {showMoreText}
        </Typography.Link>
      )}
    </div>
  ) : null;

  const verticalActionsNode = hasVerticalActions ? (
    <div
      css={{
        display: 'flex',
        gap: theme.spacing.sm,
        marginTop: theme.spacing.xs,
        marginBottom: theme.spacing.xs,
      }}
    >
      {memoizedActions}
    </div>
  ) : null;

  const descriptionBody = (
    <>
      {descriptionTextNode}
      {verticalActionsNode}
    </>
  );

  // Always pass a description element so AntD consistently applies its `.ant-alert-with-description`
  // class. The style function overrides all dist side-effects of that class. Without this, title-only
  // alerts would get different base AntD styles (icon positioning, padding, font sizes) causing layout
  // shifts. The description container is hidden via CSS when there is no content to display.
  const finalDescription = !hasDescriptionSlotContent ? (
    <></>
  ) : showCollapseToggle ? (
    <div id={descriptionRegionId} css={!isExpanded ? { display: 'none' } : undefined}>
      {descriptionBody}
    </div>
  ) : (
    descriptionBody
  );

  const alertIcon = (
    <div
      css={{
        display: 'inline-flex',
        flexDirection: 'row',
        alignItems: 'center',
        gap: theme.spacing.xs,
      }}
    >
      {showCollapseToggle && (
        <Button
          aria-expanded={isExpanded}
          aria-controls={descriptionRegionId}
          aria-label={isExpanded ? collapseToggleAriaLabel : expandToggleAriaLabel}
          componentId={componentId ? `${componentId}.collapse_toggle` : 'alert.collapse_toggle'}
          htmlType="button"
          icon={
            isExpanded ? (
              <ChevronDownIcon css={{ color: theme.colors.textSecondary }} />
            ) : (
              <ChevronRightIcon css={{ color: theme.colors.textSecondary }} />
            )
          }
          onClick={() => setIsExpanded((v) => !v)}
          size="small"
          type="tertiary"
        />
      )}
      <SeverityIcon severity={mergedProps.type} ref={elementRef} />
    </div>
  );

  return (
    <DesignSystemAntDConfigProvider>
      <AntDAlert
        {...addDebugOutlineIfEnabled()}
        {...mergedProps}
        onClose={onCloseWrapper}
        className={cx(mergedProps.className)}
        css={getAlertEmotionStyles(
          clsPrefix,
          theme,
          mergedProps.type,
          size,
          mergedProps.banner,
          hasDescriptionSlotContent,
        )}
        icon={alertIcon}
        closeText={
          mergedProps.closable && (
            <CloseSmallIcon
              ref={closeIconRef}
              aria-label={closeIconLabel}
              css={{ marginTop: placeActionsHorizontally ? theme.spacing.xs : 2 }}
            />
          )
        }
        description={finalDescription}
        message={messageWithHorizontalActions ?? mergedProps.message}
        action={mergedProps.action}
        {...dangerouslySetAntdProps}
        {...eventContext.dataComponentProps}
      />
      {showMoreContent && (
        <Modal
          title={showMoreModalTitle}
          visible={isModalOpen}
          onCancel={() => setIsModalOpen(false)}
          componentId={componentId ? `${componentId}.show_more_modal` : 'alert.show_more_modal'}
          footer={null}
          size="wide"
        >
          {showMoreContent}
        </Modal>
      )}
    </DesignSystemAntDConfigProvider>
  );
};

/**
 * Single flat style function. Antd always receives a `description` prop so `-with-description` is
 * always applied. We override every dist side-effect (icon absolute positioning, enlarged font sizes,
 * altered padding) here so there is only one layout path: flex-wrap row with the description on row 2.
 */
const getAlertEmotionStyles = (
  clsPrefix: string,
  theme: Theme,
  alertType: string | undefined,
  size: 'small' | 'large',
  isBanner: boolean | undefined,
  hasDescriptionContent: boolean,
) => {
  const isSmall = size === 'small';
  const classCloseIcon = `.${clsPrefix}-close-icon`;
  const classCloseText = `.${clsPrefix}-close-text`;
  const classDescription = `.${clsPrefix}-description`;
  const classMessage = `.${clsPrefix}-message`;
  const classIcon = `.${clsPrefix}-icon`;

  const BORDER_SIZE = theme.general.borderWidth;
  const LARGE_PADDING = theme.spacing.xs * 3;
  const SMALL_PADDING = theme.spacing.sm;
  const ICON_GAP = theme.spacing.sm;

  const styles: CSSObject = {
    // --- Layout ---
    // AntD DOM: .alert-icon | .alert-content (message + description) | .alert-close-icon
    // When there is description content, flex-start keeps icon/close aligned with the first
    // line of the message while the description flows below. Without description content,
    // center aligns icon, message (which may include inline action buttons), and close button.
    display: 'flex !important' as CSSObject['display'],
    alignItems: `${hasDescriptionContent ? 'flex-start' : 'center'} !important` as CSSObject['alignItems'],

    // --- General tokens ---
    // !important defeats dist's `.alert-with-description { padding: 7px 15px 7px 24px }`
    // which applies asymmetric padding intended for the original absolute-positioned icon layout.
    padding: isSmall
      ? `${theme.spacing.xs + BORDER_SIZE}px ${SMALL_PADDING}px !important`
      : `${LARGE_PADDING - BORDER_SIZE}px ${LARGE_PADDING}px !important`,
    boxSizing: 'border-box',
    borderRadius: theme.borders.borderRadiusSm,
    borderColor: theme.colors.border,

    // --- Icon: reset dist absolute positioning, keep at top-start ---
    [classIcon]: {
      position: 'relative !important' as CSSObject['position'],
      top: 'auto !important' as CSSObject['top'],
      left: 'auto !important' as CSSObject['left'],
      fontSize: theme.general.iconFontSize,
      display: 'inline-flex',
      alignItems: 'center',
      height: theme.typography.lineHeightBase,
      marginTop: 0,
      marginRight: ICON_GAP,
    },

    // --- Message: fill remaining space on row 1, override dist 18px ---
    [classMessage]: {
      flex: '1 1 auto',
      minWidth: 0,
      fontSize: theme.typography.fontSizeBase,
      fontWeight: theme.typography.typographyBoldFontWeight,
      lineHeight: theme.typography.lineHeightBase,
      marginBottom: 0,
    },

    // --- Description: stacks below message inside .alert-content ---
    [classDescription]: {
      lineHeight: theme.typography.lineHeightBase,
      // Hide the description container for title-only alerts. We always pass a description
      // element to AntD to keep the `.ant-alert-with-description` class applied, but when
      // there is no actual content the container must not take up space.
      ...(!hasDescriptionContent && { display: 'none' }),
    },

    // --- Close button: height matches icon/text so the centered X aligns ---
    [classCloseIcon]: {
      lineHeight: theme.typography.lineHeightBase,
      height: theme.typography.lineHeightBase,
      width: theme.general.iconFontSize,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      position: 'relative !important' as CSSObject['position'],
      top: 'auto !important' as CSSObject['top'],
      right: 'auto !important' as CSSObject['right'],
      marginLeft: ICON_GAP,
      '&:focus-visible': {
        outlineStyle: 'auto',
        outlineColor: theme.colors.actionDefaultBorderFocus,
      },
    },
    [`${classCloseText} > span`]: {
      lineHeight: theme.typography.lineHeightBase,
      height: theme.general.iconFontSize,
      width: theme.general.iconFontSize,
      fontSize: theme.general.iconFontSize,
      display: 'inline-flex',
      alignItems: 'center',
    },

    // --- Type colors ---
    ...(alertType === 'warning' && {
      color: theme.colors.textValidationWarning,
      borderColor: theme.colors.yellow300,
    }),
    ...(alertType === 'error' && {
      color: theme.colors.textValidationDanger,
      borderColor: theme.colors.red300,
    }),

    ...(alertType === 'success' && {
      color: theme.colors.textValidationSuccess,
      borderColor: theme.colors.green300,
      backgroundColor: theme.colors.backgroundSuccess,
    }),

    // --- Banner ---
    ...(isBanner && {
      borderStyle: 'solid',
      borderWidth: `${theme.general.borderWidth}px 0`,
    }),

    // --- After closed ---
    '&[data-show="false"]': {
      borderWidth: 0,
      padding: '0 !important' as CSSObject['padding'],
      width: 0,
      height: 0,
    },

    ...getAnimationCss(theme.options.enableAnimation),
  };

  return css(styles);
};
